import type { Request, Response } from 'express';
import { pool } from './db';

export interface ReportRow {
  id: number;
  title: string;
  status: string;
  ownerId: number;
}

// Fixed, trusted lookups — no caller-controlled text reaches the SQL string.
export async function listOpenReports(): Promise<ReportRow[]> {
  const result = await pool.query(
    "SELECT id, title, status, owner_id FROM reports WHERE status = 'open' ORDER BY id DESC",
  );
  return result.rows;
}

export async function reportById(id: number): Promise<ReportRow | null> {
  const result = await pool.query(
    'SELECT id, title, status, owner_id FROM reports WHERE id = $1',
    [id],
  );
  return result.rows[0] ?? null;
}

export function toSummary(rows: ReportRow[]): string {
  return rows.map((r) => `#${r.id} ${r.title} [${r.status}]`).join('\n');
}

