import type { Request, Response } from 'express';
import { fetchOrder } from './orderStore';

// Fetch a single order. On failure we return a generic message and keep
// implementation details server-side.
export async function getOrder(req: Request, res: Response): Promise<void> {
  const id = String(req.params.id);
  try {
    const order = await fetchOrder(id);
    if (!order) {
      res.status(404).json({ message: 'Order not found' });
      return;
    }
    res.json(order);
  } catch (err) {
    console.error('getOrder failed', err);
    res.status(500).json({ message: 'Could not load order' });
  }
}

