import jwt from 'jsonwebtoken';

const SECRET = process.env.JWT_SECRET as string;

export interface SessionClaims {
  sub: string;
  role: 'user' | 'admin';
}

// Mint a short-lived session token.
export function mintToken(claims: SessionClaims): string {
  return jwt.sign(claims, SECRET, { algorithm: 'HS256', expiresIn: '15m' });
}

// Read a session token — algorithm is pinned server-side, never taken from
// the token header.
export function readToken(token: string): SessionClaims {
  return jwt.verify(token, SECRET, { algorithms: ['HS256'] }) as SessionClaims;
}

