import { z } from 'zod';
import { prisma } from './prisma';

const SearchSchema = z.object({
  name: z.string().min(1).max(80).trim(),
});

export type UserSummary = { id: string; name: string };

// Look up users by a validated name fragment. Prisma binds the value — the
// `contains` filter is never string-built SQL.
export async function searchUsers(input: unknown): Promise<UserSummary[]> {
  const { name } = SearchSchema.parse(input);
  return prisma.user.findMany({
    where: { name: { contains: name } },
    select: { id: true, name: true },
  });
}

