import { createReadStream } from 'node:fs';
import path from 'node:path';
import type { Request, Response } from 'express';

const ROOT = path.resolve('/srv/exports');

// Resolve the requested name inside ROOT and reject anything that escapes it,
// so a `../` (or an absolute path) in req.query.name can never reach a target
// outside the export directory.
export function streamExport(req: Request, res: Response): void {
  const name = String(req.query.name);
  const target = path.resolve(ROOT, name);
  if (target !== ROOT && !target.startsWith(ROOT + path.sep)) {
    res.status(400).json({ message: 'Invalid path' });
    return;
  }
  createReadStream(target).pipe(res);
}

