// NOTE: ${tenantId} is interpolated into the tagged template, but this is NOT
// string-built SQL — the postgres.js `sql` tag sends the value as a bound $1
// parameter, never as query text, so it is injection-safe.
export async function countsForTenant(tenantId: string): Promise<number> {
  const rows =
    await sql`SELECT count(*) AS total FROM events WHERE tenant_id = ${tenantId}`;
  return Number(rows[0].total);
}
